## 3. Create the missing `OcrWorker` class

Create a new file `OcrWorker.kt` in your data/workers package:

```kotlin
package com.example.grocerytracker.data

import android.content.Context
import android.graphics.Bitmap
import android.graphics.ImageDecoder
import android.net.Uri
import android.os.Build
import android.provider.MediaStore
import androidx.work.Worker
import androidx.work.WorkerParameters
import androidx.work.Data

class OcrWorker(
    context: Context,
    workerParams: WorkerParameters
) : Worker(context, workerParams) {

    override fun doWork(): Result {
        val imageUris = inputData.getStringArray("IMAGE_URIS") ?: return Result.failure()

        return try {
            val uri = Uri.parse(imageUris[0])
            val bitmap = uriToBitmap(applicationContext, uri)

            // TODO: Run your OCR here (e.g., ML Kit Text Recognition)
            val extractedText = "OCR result placeholder"

            val outputData = Data.Builder()
                .putString("OCR_RESULT", extractedText)
                .build()

            Result.success(outputData)
        } catch (e: Exception) {
            Result.failure()
        }
    }

    private fun uriToBitmap(context: Context, uri: Uri): Bitmap {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.P) {
            ImageDecoder.decodeBitmap(ImageDecoder.createSource(context.contentResolver, uri))
        } else {
            @Suppress("DEPRECATION")
            MediaStore.Images.Media.getBitmap(context.contentResolver, uri)
        }
    }
}
```

